import './Header.css' //1
import Button from '../../universalComponents/Button'
//import ModeButton from './ModeButton';
import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import post2 from '../../universalComponents/post2'
const x = "Login/Sign up";

function Header() {

    const navigate = useNavigate();
    const goToLogin = () => {
        navigate("/Login");
    };

    const [text, changeText] = useState('light mode :3');

    const changeMode = () => {
        changeText((text) => {
            document.documentElement.classList.toggle("light-mode");
            if (text==="light mode :3") {
                document.documentElement.style.setProperty("--noHover", "1");
                document.documentElement.style.setProperty("--hover", "0");

                return "evil light mode >:D"
            }
            else {
                document.documentElement.style.setProperty("--noHover", "0");
                document.documentElement.style.setProperty("--hover", "1");

                return "light mode :3"
            }
        })
    }


    const [logged, dLogged] = useState(false);
    //set logged by fetching data...
    useEffect(() => {
        post2('/signedIn',{a:1}) ////////////////////////////////////////////////////////////////////////////
        .then((x) => {dLogged(x.ans)})
    },[])

    return (
        <div className = 'header'>
            <div className={logged ? 'hide' : "login"}><Button func = {goToLogin} text={x}/></div>
            <div className='mode'><Button func = {changeMode} text={text}/></div>
            {/** */}
        </div>
    )
};

export default Header;

