import Map from "./MapComponent/Map"; //1
import { useEffect, useState } from "react";
import post2 from "../../universalComponents/post2";
import After from "./MapComponent/After";
function MapComponentAfter({loc, heightMap, mapNo}) {

    const [ans, ansChange] = useState([])
    
    useEffect(() => {
        // Apply overflow: hidden when the component mounts
        document.documentElement.style.overflow = "hidden"; // <html>
        document.body.style.overflow = "hidden"; // <body>

        //get map after data and put it in the useState :D
        post2('/map0AfterData',{map : mapNo}) ////////////////////////////////////////////////////////////////////////////////////////////////////
        .then(ans => {
            ansChange([ans.title, ans.haiku1, ans.haiku2, ans.haiku3, ans.lore, ans.username, ans.poem]);
        })

        return () => {
          // Remove overflow: hidden when the component unmounts
          document.documentElement.style.overflow = "";
          document.body.style.overflow = "";
        };
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    if (ans.length===0) {
        return (<h1>Contacting server. Please wait :D</h1>)
    }

    else {
        return(
            <div className="testicle">
                <div className="balls">
                    <After title={ans[0]} haiku1={ans[1]} haiku2={ans[2]} haiku3={ans[3]} lore={ans[4]} username={ans[5]}  poem={ans[6]} />
                </div>
                <Map loc={loc} heightMap={heightMap}/>
            </div>
        )

    }
}
export default MapComponentAfter;