
import './Before.css';  //3
import { useEffect, useState } from 'react';
import ToggleButton from '../../../universalComponents/ToggleButton';
import post2 from '../../../universalComponents/post2';





function Before({user, reserved, mapNo, poem}) {
  const handleSubmit = async (e) => {
    //FIRST CHECK IF USER IS STILL ALLOWED TO SUBMIT!! OT ELSE ITS...YK... GONNA BE AN ISSUE...MEH NAH. /
    e.preventDefault();
    const formData = {
      //should probably send username instead
        mapNo: mapNo,
        username: user,
        lore: e.target.lore?.value,
        title: e.target.title?.value,
        haiku1: e.target.haiku1?.value,
        haiku2: e.target.haiku2?.value,
        haiku3: e.target.haiku3?.value
    };
    post2('/send', formData) ////////////////////////////////////////////////////////////////////////////////////////////////////
    .then((data) => {

      if (data.haikuGood && data.contentGood) 
        {//means that haiku and title and lore was acceptable :D

          window.location.reload()
        }
    
      else {
        if (!data.haikuGood) {
          dMsgg("Sorry. Haiku not accepted. Please ensure the syllables are in the pattern 5-7-5. \nOr change words, as our haiku bot may not be smart enough.")
        }

        if (!data.contentGood) {

          dMsgg("Rejected: " + data.modMsg)
        }
      }

    }
  )
    .catch(e=> {console.log("Uh oh,, errror at Before.js line 46 :c ")})
  }

    const [showTextbox, setShowTextbox] = useState(false);
    const [showHaiku, setShowHaiku] = useState(false);
    const [showTitle, setShowTitle] = useState(false);
    const [showPoem, setShowPoem] = useState(false);
    const [popup, dPopup] = useState(true)

    //reserve button
    const [res, dRes] = useState(false);
    //submit button
    const [submit, dSubmit] = useState(false);
    //message
    const [msggs, dMsgg] = useState('you get access to submission only after you reserve.')


    useEffect(() => {
  
      if (!user) {
        dMsgg("log in to reserve & submit");
        return;
      }
  
      if (!reserved) {
        dRes(true);
        dMsgg("you get access to submission only after you reserve.");
        return;
      }
  
      if (reserved === user) {
        dSubmit(true);
        dMsgg("You reserved. Submit button now accessible.");
      } else {
        dMsgg(`Sorry. This map has been reserved by ${reserved}`);
      }
    }, [user, reserved]); // 👈 Add dependencies to re-run when `user` or `reserved` changes

    const reserve = () => {
      post2('/map0InitData', {mapNo: mapNo}) ////////////////////////////////////////////////////////////////////////////////////////////////////
            .then(data => {
              let reserved =  data.reserved;
              dRes(false);

              if (reserved==null) {
                post2('/reserveMap0', {mapNo: mapNo,user: user}) ////////////////////////////////////////////////////////////////////////////////////////////////////
                .then((allowed) => {


                  if (!allowed.a) {
                  dMsgg("Oi! You already reserved someplace else, didn't you 😏 \n"+ 
                    "sorry. You can only reserve after your previous reservation has expired :c");
                  }

                  else {
                    dSubmit(true)
                    dMsgg("You reserved. Submit button now accessible.");
                  }
                });
              }


              else {
                dRes(false);
                dMsgg("Sorry. This map has been reserved.");

              }

            })
    }

  return (
    <form onSubmit={handleSubmit}>
      <div className="loreBefore">
      <ToggleButton x={showTextbox} dX = {setShowTextbox} t1={"Show textbox"} t2={"Hide textbox"}/>
      <textarea name="lore" placeholder="Enter lore here..." rows="10" cols="80" className={showTextbox ? "lore1" : "hide"} required></textarea>
      </div>

      <div className="haikuBefore">
        <ToggleButton x={showHaiku} dX = {setShowHaiku} t1={"Show haiku box"} t2={"Hide haiku box"}/>
        <input type="text" name="haiku1" placeholder="Enter haiku line 1 here..." className={ showHaiku ? "haiku1" : "hide"} required></input>
        <input type="text" name="haiku2" placeholder="Enter haiku line 2 here..." className={ showHaiku ? "haiku2" : "hide"} required></input>
        <input type="text" name="haiku3" placeholder="Enter haiku line 3 here..." className={ showHaiku ? "haiku3" : "hide"} required></input>
        <ToggleButton x={showPoem} dX = {setShowPoem} t1={"Show poem"} t2={"Hide poem"}/>
        <div className={ showPoem ? 'poem1' : "hide"}>{poem}</div>

      </div>

      <div className={popup ? "popup" : "hide"}>
        <div className="popupTitle">
          <div>Expedition 0</div>
          <button onClick={() => dPopup(false)}>X</button>
        </div>
        <div className="popupContent">
          <p>
            How to play the game: <br />
            <b>0- HAVE FUN FOR GOD'S SAKE!:</b> Ideally, the opportunity to just puke whatever you want to, onto this website should
            make you feel at the very least- a vague sense of an unidentifiable positive emotion. This is your world*
            (one map limited for one hour terms and conditions apply)!!! Interpret the poem in your own way! do your own
            thing! :D
          </p>
          <p>
            <b>1- Login/Sign up!!:</b> You won't be able to submit the stuff you make for the world to see, if you don't sign
            up/log in.
          </p>
          <p>
            <b>2- Reserve!!!:</b> (if map not reserved yet) if you see a map whose lore you like, check the message near the 
            'reserve' button to see if its open for reservation or not. If it's not reserved, reserve it so that you have the map 
            ALL TO YOURSELF for the next hour 💗. WARNING: If you reserve a map, you will not be able to reserve any other 
            map for the next hour. (timer coming in Expedition 1.0)
          </p>
          <p>
            <b>3- Submit!!!!!:</b> After typing your heart out and filling all the blanks, submit the page! <br />
            If you have not typed any gibberish, your work will be accepted and proudly put on display, on our map, for the
            world to see...well, this place is practically a desert. So...not exactly the world..but hey! I-I'll definitely <b />
            read it!! 🥲
          </p>
        </div>
      </div>


      <div className="titleBefore">
        <ToggleButton x={showTitle} dX = {setShowTitle} t1={"Show title box"} t2={"Hide title box"}/>
        <input type="text" name="title" placeholder="Enter title here..." className={ showTitle ? "title1" : "hide"} required></input>
      </div>

      <div className="submitBefore">
        <input type='submit' className={submit ? 'submitButton': 'no-interaction'} />
        <button className={res ? 'reserveButton': 'no-interaction'} onClick={reserve}>Reserve</button>
      <div className="mesage">{msggs}</div></div> 
    </form>
  );
}
///*{ showTitle ? "title1" : "hide"} */
export default Before;

