import { useNavigate } from 'react-router-dom';
import './MapCard.css'

function MapCard({src, num, mapName="Unexplored"}) {

    const navi = useNavigate();

    const navigateTo = () => {
        navi(`/0/${num}`)
    }
    return (
        <div className="mapCard"  onClick={navigateTo}> 
            <img src={src} alt="Map" />
            <div className="mapName">{mapName}</div>
        </div>
    )
}


export default MapCard;
