import Map from "./MapComponent/Map"; //1
import { useEffect, useState } from "react";
import Before from "./MapComponent/Before";
import post2 from "../../universalComponents/post2";
function MapComponentBefore({mapNo, loc, heightMap}) { 

    const [init, dInit] = useState([])
        // Apply overflow: hidden when the component mounts
        document.documentElement.style.overflow = "hidden"; // <html>
        document.body.style.overflow = "hidden"; // <body>

        useEffect(() => {
            post2('/map0InitData', {mapNo: mapNo}) //http://localhost:6969
            .then(data => {dInit([data.poem,data.user,data.reserved])}) ////////////////////////////////////////////////////////////////////////////////////////////////////
    
        return () => {
          // Remove overflow: hidden when the component unmounts
          document.documentElement.style.overflow = "";
          document.body.style.overflow = "";
        };
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);


    return(
        <div className="testicle">

            <div className="balls">

                <Before mapNo={mapNo} poem={init[0]} user={init[1]} reserved={init[2]}/>

            </div>
            <Map loc={loc} heightMap={heightMap}/>
        </div>
    )
}
export default MapComponentBefore;