import React, { useRef, useEffect } from 'react';
import * as d3 from 'd3';

function Map({ loc, heightMap }) {
  // Create a ref to attach to the SVG element
  const svgRef = useRef(null);

  // Move all D3 manipulation to useEffect
  useEffect(() => {
    // Store a reference to the current DOM node
    const svgNode = svgRef.current;
    
    // Clear any existing SVG content to prevent duplicates
    d3.select(svgNode).selectAll("*").remove();

    // Get dimensions
    let width = document.documentElement.clientWidth;
    let height = document.documentElement.clientHeight;
    let color = d3.scaleSequential(d3.interpolateSpectral);

    // Select the SVG through the stored node instead of using the ref directly
    let svg = d3.select(svgNode)
      .attr("width", width)
      .attr("height", height);

    let content = svg.append("g");

    /*/ DON'T NEED ZOOM...YET :c
    const zoom = d3.zoom()
      .scaleExtent([1, 2.5])
      .translateExtent([[0, 0], [width, height]])
      .on("zoom", zoomed);

    // Apply the zoom behavior to the group element
    content.call(zoom);

    // Zoom event callback function
    function zoomed(event) {
      content.attr("transform", event.transform);
    }
*/
    // Create Voronoi diagram
    let delaunay = d3.Delaunay.from(loc),
        voronoi = delaunay.voronoi([0, 0, width, height]),
        polygons = loc.map((_, i) => voronoi.cellPolygon(i));

    // Coloring in the map
    content.selectAll("path")
      .data(polygons)
      .enter().append("path")
      .attr("d", (d) => {
        return d ? `M${d.join("L")}Z` : null;
      })
      .attr("stroke", (_, i) => color(1 - heightMap[i]))
      .attr("fill", (_, i) => color(1 - heightMap[i]));

    // Cleanup function using the stored node reference
    return () => {
      // Using the stored reference to ensure we're cleaning up the right node
      if (svgNode) {
        d3.select(svgNode).selectAll("*").remove();
      }
    };
  }, [loc, heightMap]); // Re-run effect when loc or heightMap changes

  // Return an actual SVG element for React to manage
  return <svg ref={svgRef}></svg>;
}

export default Map;


