import { useState, useEffect } from "react";
function TypedWords( {text, ms}) {
    let [val, newVal] = useState('');



    useEffect(() => {
        let x = setInterval(() => {
            newVal((prev) => {
                if (prev.length < text.length) {
                    return prev + text[prev.length]; // Use prev.length to track position
                } else {
                    clearInterval(x);
                    return prev;
                }
            });
        }, ms);
    
        return () => clearInterval(x); // Cleanup interval on unmount
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const formattedHaiku = val.split('\n').map((line, index) => (
        <span key={index}>
            {line}
            <br />
        </span>
    ));
    return (
        <>
        {formattedHaiku}</>
    )


};

export default TypedWords;



/*
HOW THE RENDERING CASCADE WORKS, becuase now that we included useState and useEffect,
things have gotten a lil zbizy T-T

Initial Render:

The TypedWords component is called with text and ms as props.
The useState hook initializes val to an empty string ('').
The useEffect hook is defined but not executed yet.
The formattedHaiku variable is calculated based on the initial value of val (which is an empty string), resulting in an empty array.
The JSX in the return statement is rendered, displaying the initial state of the component (an empty span).
useEffect Execution:

After the initial render, the useEffect hook runs.
The setInterval function is set up to update val every ms milliseconds.
The interval function updates val character by character from the text string.
Each time val is updated, the component re-renders.
Subsequent Renders:

On each re-render, the formattedHaiku variable is recalculated based on the current value of val.
The val.split('\n') method splits val into lines wherever it encounters a \n character.
The JSX in the return statement is rendered again, displaying the updated state of the component.
Completion:

The interval continues to update val until the entire text string is displayed.
Once val reaches the length of the text, the interval is cleared, and the updates stop.


*/