import './Expeditions.css'
import Header from './Expeditions/Header';
import MapCard from './Expeditions/MapCard';
import Title from './Expeditions/Title';
import post2 from '../universalComponents/post2';
import { useEffect, useState } from 'react';
function Expeditions() {
    //get an array of all the titles.
    // then make a for loop for the titles and if titles==null: type unexplored.
    // else, type the title :D.
    const [show, dShow] = useState(false)
    const [ans, dAns] = useState([])


    useEffect(() => {

        //get all the titles
        post2(`/getTitles0`, {a:1}) ////////////////////////////////////////////////////////////////////////////////////////////////////
        .then(data => { //http://localhost:6969
            let titles = data.titles
            let ans = Array.from({length: 16}, (_,i) => {
                return <MapCard mapName={(titles[i]==null) ? 'Unexplored' : titles[i]} src={`/images/test/${i + 1}.jpg`} num={i + 1}  />
            })
            dAns(ans)
            dShow(true);
        })
        
    },[])

    if (!show) {
        return(<p>Loading...</p>)
    }

    else {

        
        return (
        <>
            <Header />
            <Title />
            <div class="maps">{ans}</div>
        </>
        )}

}

export default Expeditions;