import { useParams } from "react-router-dom"; //1
import { useEffect, useState } from "react";
import MapComponentBefore from "./Maps/MapComponentBefore";
import MapComponentAfter from "./Maps/MapComponentAfter";
function Maps() {

    const [ans, changeAns] = useState([])
    //availability i.e if the map was already written or not :C
    const [av, changeAv] = useState(false)
    const { num } = useParams();
    const numInt = parseInt(num)
    const getMap = {map: numInt,//,
        expedition: "zero"
    }


    useEffect(() => {

        fetch('/map0', { ////////////////////////////////////////////////////////////////////////////////////////////////////
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(getMap),
        })
          .then((response) => response.json())  // Convert the response to JSON
          .then((data) => {
            changeAns(data.ans)
            changeAv(data.availability)
            console.log("PEANIS!!")
        })
          .catch((error) => {
            console.error("Error:", error);  // Handle any errors here
          });
      // eslint-disable-next-line react-hooks/exhaustive-deps
      }, []);

    if (num > 16 || num < 1) {
        return <h1>No map exists with this ID BRO D:</h1>;  
    } 
    
    
    else {
        
        if (ans.length===0) {
            return <h1>contacting server...please wait :D </h1>
        }
        else {
          if (av) { 
            return <MapComponentBefore mapNo={numInt} loc={ans[0]} heightMap={ans[1]}/>
          } 

          else {
            return <MapComponentAfter loc={ans[0]} heightMap={ans[1]} mapNo={numInt}/>
          }

        
        
        
    }
  }

}

export default Maps;