import { useNavigate } from "react-router-dom"; //1
import '../Login.css'
import TypedWords from "../../universalComponents/TypedWords";
import { useEffect, useState } from "react";
import msgs from "../../universalComponents/messages";

function Authenticate({username,email, password}) {
    //IF NO EMAIL, THEN REDIRECT TO HOME PAGE. ELSE,
      
    // good job :D
    // this should keep the authenticator nice and secure :D.
    const nav = useNavigate();
    const [msg,dMsg] =  useState(null);
    const [error, dError] = useState("")
    let phrases= msgs.authenticate;

    useEffect(() => {
        dMsg(Math.floor(Math.random()*phrases.length))
    // eslint-disable-next-line react-hooks/exhaustive-deps
    },[])

    if (msg===null) {
        return(<p>Loading...</p>)
    }

    
    const handleSubmit = async (e) => {

        e.preventDefault();

        //first send code to te backend
        const  formData = {
            code: e.target.code?.value,
            username: username,
            email: email,
            password: password
        }

        await fetch('/authenticateCode', { ////////////////////////////////////////////////////////////////////////////////////////////////////
            method: 'POST',
            credentials: 'include',
            headers: {
                'Content-Type': 'application/json'
            },

            body: JSON.stringify(formData)

        })
        .then(data => data.json())
        .then(data => {
            let x = data.status
            if (!x) {
                dError("Sorry. Wrong and/or expired code. Please try again and use the code from the \n latest email we have sent you. \n \n" +
                    "Or click on the 'start over button' if you suspect using an expired code.")
            }
            else {
                nav('/')
            }
            
        });
    }

    const startOver = () => {
        window.location.reload();
    }

    return (

        <form className="loginContainer" onSubmit={handleSubmit} >
            <div className="topCentre">Sign up
            <br /><div className="goHome" onClick={() => {nav('/')}} title="Click to go back to the home page">home</div>
            </div>
            <div className="loginElements">
                <div>Please check for an email from 'altexpeditions'. Especially the spam section</div>
                <TypedWords text={phrases[msg][0]} ms={phrases[msg][1]}/>
                <input type="text" placeholder="Enter code here" name = 'code' maxLength={6} required/>
                <div className='fail'>{error}</div>
                <div className="buttons">
                <button onClick={startOver}>Start over</button>
                    <input type="submit" />
                </div>        
            </div>
        </form>
    );
}

export default Authenticate;