import './After.css'
import ToggleButton from '../../../universalComponents/ToggleButton'
import { useState } from 'react';
function After({title, haiku1, haiku2, haiku3, lore, username, poem}) {  

    const [showTextbox, setShowTextbox] = useState(false);
    const [showHaiku, setShowHaiku] = useState(false);
    const [showTitle, setShowTitle] = useState(false);
    const [showPoem, setShowPoem] = useState(false);

    return(
        <div className="after">

            <div className='haikuAfter'>
                <ToggleButton x={showHaiku} dX = {setShowHaiku} t1={"Show haiku box"} t2={"Hide haiku box"}/>
                <div className={ showHaiku ? "hAfter" : "hide"}>{haiku1}<br /> {haiku2} <br /> {haiku3}</div>

                <ToggleButton x={showPoem} dX = {setShowPoem} t1={"Show poem"} t2={"Hide poem"}/>
                <div className={ showPoem ? 'pAfter' : "hide"}>{poem}</div>
            </div>


            <div className="loreAfter">
                <ToggleButton x={showTextbox} dX = {setShowTextbox} t1={"Show textbox"} t2={"Hide textbox"}/>
                <div className={showTextbox ? "lAfter" : "hide"}>{lore}</div>
            </div>

            <div className="titleAfter">
                <ToggleButton x={showTitle} dX = {setShowTitle} t1={"Show title box"} t2={"Hide title box"}/>
                <div className={ showTitle ? 'tAfter'  : "hide"}>{title}</div>
            </div>

            <div className="makerAfter">Created by {username}</div>
        </div>
    )
}

export default After