import Button from "../universalComponents/Button"; //1
import { useNavigate } from "react-router-dom";
import './Login.css'
import TypedWords from "../universalComponents/TypedWords";
import { useState, useEffect } from "react";
import msgs from "../universalComponents/messages";


function Login() {
    const nav = useNavigate();
    //first check if user is already logged in
    const [msg,dMsg] =  useState(null)
    const [fail, dFail] = useState(false); //the message that 
    let phrases= msgs.login;



    const handleSubmit= async (e) => {
        //get their info then log
        e.preventDefault();
        const  formData = {
            email: e.target.email?.value,
            password: e.target.password?.value
        }
        let ans=await fetch('/loginn', { ////////////////////////////////////////////////////////////////////////////////////////////////////
            method: 'POST',
            credentials: "include",
            headers: {
                'Content-Type': 'application/json',
            },
    
            body: JSON.stringify(formData)
        })
        .then(data => data.json());
        ans=ans.ans;
    
        if (ans) {
            console.log("ooo..the ghost is still here")
            nav('/')
        }
        else {
            dFail(true)
        }
    }




    //now we gotta create the login nonsense :c

    useEffect(() => {
            dMsg(Math.floor(Math.random()*phrases.length))
        // eslint-disable-next-line react-hooks/exhaustive-deps
        },[])

    if (msg===null) {
        return(<p>Loading..</p>)
    }
    
    return (
        <form className="loginContainer" onSubmit={handleSubmit}>
            <div className="topCentre">Login
            <br /><div className="goHome" onClick={() => {nav('/')}} title="Click to go back to the home page">home</div>
            </div>
            <div className="loginElements">

                <TypedWords text={phrases[msg][0]} ms={phrases[msg][1]}/>

                <input type="email" placeholder="Email" name = 'email' required/>
                <input type="password" placeholder="Password" name='password' required/>

                <div className={fail ? 'fail' : 'hide'}>nope. you failed. sorry :c</div>

                <div className="buttons">
                    <Button func={() => nav('/Signup')} text={"Sign Up"} />
                    <input type="submit" />
                </div>
                    
            </div>
        </form>
    );
}

export default Login;
