import Button from "../universalComponents/Button"; //1
import { useNavigate } from "react-router-dom";
import './Login.css'
import TypedWords from "../universalComponents/TypedWords";
import { useEffect, useState } from "react";
import msgs from "../universalComponents/messages";
import Authenticate from "./Signup/Authenticate";

function Signup() {
    
    const nav = useNavigate();
    const [msg,dMsg] =  useState(null);
    const [error, dError] = useState("")
    const [auth, dAuth]= useState(false)
    const [userData, dUserData] = useState([])
    let phrases= msgs.signUp;

    useEffect(() => {
        dMsg(Math.floor(Math.random()*phrases.length))
    // eslint-disable-next-line react-hooks/exhaustive-deps
    },[])

    if (msg===null) {
        return(<p>Loading...</p>)
    }

    
    const handleSubmit = async (e) => {

        e.preventDefault();
        let us = e.target.username?.value;
        let em = e.target.email?.value
        let pa = e.target.password?.value;
        //first send user data to backend
        const  formData = {
            username: us,
            email: em,

        }

        await fetch('/signupp', { ////////////////////////////////////////////////////////////////////////////////////////////////////
            method: 'POST',
            credentials: 'include',
            headers: {
                'Content-Type': 'application/json'
            },

            body: JSON.stringify(formData)

        })
        .then(data => data.json())
        .then(data => {
            let x = data.status
            // eslint-disable-next-line eqeqeq
            if (x==0) {
                dError("Yep. You're all good G. Nobody wiyh this username/email exist :D")
                dAuth(true);
                dUserData([us,em, pa])
                //ookay. This means that all the data 
            }
            // eslint-disable-next-line eqeqeq
            else if (x==2) {
                dError("Username already taken :c")
            }
            // eslint-disable-next-line eqeqeq
            else if (x==1) {
                dError("email already taken :c")
            }
            else {
                dError("both email and username already taken :c")
            }
        });
    }

    if (auth) {
        return <Authenticate username={userData[0]}  email={userData[1]} password={userData[2]}/>
    }

    else {

        return (

            <form className="loginContainer" onSubmit={handleSubmit} >
                <div className="topCentre">Sign up
                <br /><div className="goHome" onClick={() => {nav('/')}} title="Click to go back to the home page">home</div>
                </div>
                <div className="loginElements">
                    <TypedWords text={phrases[msg][0]} ms={phrases[msg][1]}/>
                    <input type="text" placeholder="Username" name = 'username' minLength={4} maxLength={12} required/>
                    <input type="email" placeholder="Email" name = 'email' required/>
                    <input type="password" placeholder="Password" name='password' minLength={4} maxLength={25} required/>
                    <div className='fail'>{error}</div>
                    <div className="buttons">
                        <Button func={() => nav('/Login')} text={"Login"} />
                        <input type="submit" />
                    </div>
                        
                </div>
            </form>
        );

    }
}

export default Signup;